// Build gamification config
const aiResponseText = $input.first().json.content;
let strategy;

try {
  const cleaned = aiResponseText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
  strategy = JSON.parse(cleaned);
} catch (e) {
  const cart = $input.all()[0].json;
  strategy = {
    element: cart.cart_value > 75 ? 'spin_wheel' : 'progress_bar',
    discount: cart.customer_type === 'vip' ? '15%' : '10%',
    probability: cart.customer_type === 'vip' ? 0.8 : 0.5,
    message: 'Spin to win a discount!',
    ui_config: {}
  };
}

const checkout = $input.all()[0].json;

// Generate discount code
const discountCode = 'SPIN' + Math.random().toString(36).substring(2, 8).toUpperCase();

// Parse discount percentage for Shopify price rule
const discountStr = strategy.discount || '10%';
let discountPercent = 10;
if (discountStr !== 'free_shipping') {
  discountPercent = parseFloat(discountStr.replace('%', '')) || 10;
}

// Progress bar
const progressPercent = Math.min(100, (checkout.cart_value / checkout.free_shipping_threshold) * 100);
const remainingForFreeShipping = Math.max(0, checkout.free_shipping_threshold - checkout.cart_value);

return [{
  json: {
    checkout_id: checkout.checkout_id,
    gamification_type: strategy.element,
    discount_code: discountCode,
    discount_value: strategy.discount,
    discount_percent: discountPercent,
    is_free_shipping: discountStr === 'free_shipping',
    probability: strategy.probability,
    message: strategy.message,
    ui_config: {
      show_progress_bar: true,
      progress_percent: progressPercent,
      remaining_for_free_shipping: remainingForFreeShipping,
      show_spin_wheel: strategy.element === 'spin_wheel',
      show_mystery_box: strategy.element === 'mystery_box',
      wheel_segments: [
        { label: '10% OFF', value: '10%' },
        { label: '5% OFF', value: '5%' },
        { label: 'Free Shipping', value: 'free_shipping' },
        { label: 'Try Again', value: null }
      ]
    },
    engagement_score: checkout.cart_value > 100 ? 10 : checkout.cart_value > 50 ? 7 : 5,
    created_at: new Date().toISOString()
  }
}];
